/* Views/Product/Details.cshtml */
@model MyStore.Web.Controllers.ProductDetailsViewModel
@{
    ViewBag.Title = Model.ProductName;
}

<h2>@Model.ProductName</h2>

<section id="reviews">
    <h3>Reviews (@Model.Reviews.Count)</h3>

    @if (!Model.Reviews.Any())
    {
        <p>No reviews yet.</p>
    }
    else
    {
        foreach (var r in Model.Reviews)
        {
            <article class="review">
                <header>
                    <strong>@r.UserName</strong>
                    <span> - @r.Rating/5</span>
                    <time datetime="@r.CreatedUtc.ToString("o")">(@r.CreatedUtc.ToLocalTime().ToString("g"))</time>
                </header>
                <div class="review-body">
                    @Html.Raw(r.BodyHtml)
                </div>
            </article>
        }
    }
</section>